        graph[u].push(v);
        graph[v].push(u);
    }

    // DSU (Disjoint Set Union) to find connected components
    const parent: number[] = Array(c + 1).fill(0).map((_, i) => i);
    const rank: number[] = Array(c + 1).fill(1);

    function find(x: number): number {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x: number, y: number): void {
        const xRoot = find(x);
        const yRoot = find(y);
        if (xRoot === yRoot) return;

        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
