            parent[yRoot] = xRoot;
            rank[xRoot] += rank[yRoot];
        }
    }

    // Build DSU based on connections
    for (const [u, v] of connections) {
        union(u, v);
    }

    // For each component, store the minimum id
    const componentMin: number[] = Array(c + 1).fill(0).map((_, i) => i);

